	private Map<String, Set<String>> collectReferencedColumns(Set<String> sourceIds, List<MappingSpec> mappings) {
		Map<String, Set<String>> columnsBySource = new LinkedHashMap<>();
		for (String sourceId : sourceIds) {
			columnsBySource.put(sourceId, new LinkedHashSet<>());
		}
		for (MappingSpec mapping : mappings) {
			for (String sourceId : sourceIds) {
				columnsBySource.get(sourceId).addAll(mapping.getReferencedColumns(sourceId));
			}
		}
		return columnsBySource;
	}

	private Map<String, SourceSpec> buildSourceSpecs(Map<String, SourceDraft> sourceDrafts,
			Map<String, Set<String>> referencedColumns) throws IOException {
		Map<String, SourceSpec> sources = new LinkedHashMap<>();
		for (SourceDraft sourceDraft : sourceDrafts.values()) {
			Map<String, String> columnTypes = new LinkedHashMap<>();
			long rowCount = 0;
			for (Path path : sourceDraft.paths) {
				if (!Files.exists(path)) {
					throw new IllegalArgumentException("Referenced parquet file does not exist: " + path);
				}
				ParquetMetadata metadata = ParquetFileReader.readFooter(new LocalInputFile(path),
						ParquetMetadataConverter.NO_FILTER);
				MessageType schema = metadata.getFileMetaData().getSchema();
				rowCount += metadata.getBlocks().stream().mapToLong(block -> block.getRowCount()).sum();
				for (String column : referencedColumns.getOrDefault(sourceDraft.id, Set.of())) {
					if (!schema.containsPath(new String[] { column })) {
						throw new IllegalArgumentException(
								"Parquet source " + sourceDraft.id + " is missing required column " + column + " in "
										+ path);
					}
					Type type = schema.getType(column);
					String typeDescription = normalizeType(type);
					String existing = columnTypes.putIfAbsent(column, typeDescription);
					if (existing != null && !existing.equals(typeDescription)) {
						throw new IllegalArgumentException("Parquet source " + sourceDraft.id
								+ " has incompatible schemas for column " + column + ": " + existing + " vs "
								+ typeDescription);
					}
				}
			}
			sources.put(sourceDraft.id, new SourceSpec(sourceDraft.id, sourceDraft.paths, columnTypes, rowCount));
		}
		return Map.copyOf(sources);
	}

	private void validateJoinTypes(List<MappingSpec> mappings, Map<String, SourceSpec> sources) {
		for (MappingSpec mapping : mappings) {
			for (JoinSpec join : mapping.getJoins()) {
				String parentSourceId = mapping.getAliasToSourceId().get(join.getParentAlias());
				SourceSpec parentSource = sources.get(parentSourceId);
				SourceSpec joinedSource = sources.get(join.getSourceId());
				for (JoinCondition condition : join.getConditions()) {
					String parentType = parentSource.getColumnTypes().get(condition.getParentColumn().getColumn());
					String joinedType = joinedSource.getColumnTypes().get(condition.getSourceColumn().getColumn());
					if (!Objects.equals(parentType, joinedType)) {
						throw new IllegalArgumentException(
								"Join " + mapping.getId() + " has incompatible key types between "
										+ condition.getParentColumn().getAlias() + "."
										+ condition.getParentColumn().getColumn() + " ("
										+ parentType + ") and " + condition.getSourceColumn().getAlias() + "."
										+ condition.getSourceColumn().getColumn() + " (" + joinedType + ")");
					}
				}
			}
		}
	}

	private String normalizeType(Type type) {
		StringBuilder builder = new StringBuilder(type.getRepetition().name());
		builder.append('|');
		if (type.isPrimitive()) {
			builder.append(type.asPrimitiveType().getPrimitiveTypeName().name());
			builder.append('|').append(String.valueOf(type.asPrimitiveType().getOriginalType()));
			builder.append('|').append(String.valueOf(type.getLogicalTypeAnnotation()));
			return builder.toString();
		}
		builder.append("GROUP");
		return builder.toString();
	}

	private void logWarnings(Path mappingFile, List<String> warnings) {
		if (warnings.isEmpty()) {
			return;
		}
		StringBuilder builder = new StringBuilder("Parquet mapping warnings in ").append(mappingFile).append(':');
		for (String warning : warnings) {
			builder.append(System.lineSeparator()).append(" - ").append(warning);
		}
		logger.warn(builder.toString());
	}

	private static void warnUnknownFields(ObjectNode node, String pointer, Set<String> knownFields,
			List<String> warnings) {
		node.fieldNames().forEachRemaining(fieldName -> {
			if (!knownFields.contains(fieldName)) {
				warnings.add((pointer.isEmpty() ? "/" : pointer + "/") + fieldName + " is ignored");
			}
		});
	}

	private static ObjectNode requireObject(JsonNode node, String pointer) {
		if (!(node instanceof ObjectNode)) {
			throw new IllegalArgumentException(pointer + " must be a JSON object");
		}
		return (ObjectNode) node;
	}

	private static ObjectNode requireObject(ObjectNode parent, String fieldName, String pointer) {
		JsonNode child = parent.get(fieldName);
		if (child == null) {
			throw new IllegalArgumentException(pointer + " is required");
		}
		return requireObject(child, pointer);
	}

	private static ArrayNode requireArray(ObjectNode parent, String fieldName, String pointer) {
		JsonNode child = parent.get(fieldName);
		if (!(child instanceof ArrayNode)) {
			throw new IllegalArgumentException(pointer + " must be an array");
		}
		return (ArrayNode) child;
	}

	private static ArrayNode optionalArray(ObjectNode parent, String fieldName) {
		JsonNode child = parent.get(fieldName);
		if (child == null) {
			return null;
		}
		if (!(child instanceof ArrayNode)) {
			throw new IllegalArgumentException("/" + fieldName + " must be an array");
		}
		return (ArrayNode) child;
	}

	private static String requireText(ObjectNode parent, String fieldName, String pointer) {
		JsonNode child = parent.get(fieldName);
		if (child == null || !child.isTextual() || child.textValue().isBlank()) {
			throw new IllegalArgumentException(pointer + " must be a non-blank string");
		}
		return child.textValue();
	}

	private static int present(ObjectNode parent, String fieldName) {
		return parent.has(fieldName) ? 1 : 0;
	}

	private static ColumnRef reference(JsonNode node, String pointer, Set<String> aliases) {
		if (node == null || !node.isTextual()) {
			throw new IllegalArgumentException(pointer + " must be a string");
		}
		ColumnRef reference = ParquetStoreMapping.parseColumnReference(node.textValue(), pointer);
		if (!aliases.contains(reference.getAlias())) {
			throw new IllegalArgumentException(pointer + " references unknown alias " + reference.getAlias());
		}
		return reference;
	}

	private static IRI iri(String value, Map<String, String> prefixes, String pointer) {
		return SimpleValueFactory.getInstance().createIRI(ParquetStoreMapping.resolveIri(value, prefixes, pointer));
	}

	private static TermType parseTermType(String value, String pointer) {
		if ("iri".equals(value)) {
			return TermType.IRI;
		}
		if ("literal".equals(value)) {
			return TermType.LITERAL;
		}
		throw new IllegalArgumentException(pointer + " must be iri or literal");
	}

	private static void requireSourceId(String sourceId, Set<String> sourceIds, String pointer) {
		if (!sourceIds.contains(sourceId)) {
			throw new IllegalArgumentException(pointer + " references unknown source " + sourceId);
		}
	}

	private static final class SourceDraft {

		private final String id;
		private final List<Path> paths;

		private SourceDraft(String id, List<Path> paths) {
			this.id = id;
			this.paths = List.copyOf(paths);
		}
	}
